        // ==================== ৫. বৃহস্পতি (২০-২৫ বাক্য) ====================
        this.predictions.jupiter = {
            1:{type:"অশুভ",summary:"ভয় ও আত্মবিশ্বাসের অভাব",time:"এক বৎসর",full:`বৃহস্পতি এখন আপনার জন্মরাশিতে অবস্থান করছে, আপনার অস্তিত্বের কেন্দ্রে গুরু গ্রহের এই আগমন সাধারণত শুভ হলেও জন্মরাশিতে এর অবস্থান কিছু চ্যালেঞ্জ তৈরি করবে। এই এক বৎসর আপনি আত্মবিশ্বাসের অভাবে ভুগতে পারেন, অকারণে ভয় পেতে পারেন এবং নিজের যোগ্যতা নিয়ে সন্দেহ জাগতে পারে। আপনার স্থূলতা বা ওজন বৃদ্ধি হতে পারে, অলসতা ও বিলাসপ্রবণতা আপনাকে গ্রাস করতে পারে এবং আপনি হয়তো বড় বড় স্বপ্ন দেখবেন কিন্তু তা বাস্তবায়নের শক্তি পাবেন না। পিতার স্বাস্থ্য বা গুরুর সাথে সম্পর্ক নিয়ে উদ্বেগ আসতে পারে, মনে হবে আপনি যেন এক জায়গায় আটকে আছেন। কিন্তু মনে রাখবেন, বৃহস্পতি গুরুর প্রতীক—আর গুরু কখনো শিষ্যের ক্ষতি করেন না, তিনি শুধু পরীক্ষা নেন। নিজেকে খুব বড় ভাবার আগে ছোট হতে শিখুন, গুরুজনের পরামর্শ নিন, ধর্মগ্রন্থ পাঠ করুন এবং অলসতা ছেড়ে সক্রিয় হোন। এই এক বৎসর ধৈর্য ও বিনয়ের শিক্ষা নিলে পরবর্তী জীবনে আপনি আরও শক্তিশালী হয়ে উঠবেন। মধ্যকালে ফল বিশেষভাবে অনুভূত হবে।`},
            2:{type:"শুভ",summary:"অর্থলাভ ও বাণী মাধুর্য",time:"এক বৎসর",full:`বৃহস্পতি এখন আপনার দ্বিতীয় ভাবে অবস্থান করছে, ধন-সম্পদ ও বাকশক্তির এই ভাবে গুরু গ্রহের গোচর আপনার আর্থিক জীবনে এক স্বর্ণালী যুগের সূচনা করবে। এই এক বৎসর আপনার মুখ থেকে যেন অমৃত বর্ষিত হবে, আপনার বাকশক্তি এতটাই মধুর ও প্রভাবশালী হবে যে মানুষ আপনার কথা শুনতে ভিড় করবে। আপনি অর্থলাভ করবেন, পরিবারে সুখ-শান্তি বজায় থাকবে এবং জ্ঞান, ধর্ম বা শিক্ষা সংক্রান্ত কাজ থেকে প্রচুর আয় হবে। সোনা, রত্ন বা মূল্যবান ধাতুর ব্যবসা লাভজনক হবে, আপনার আর্থিক অবস্থা ধীরে ধীরে শক্তিশালী হবে এবং আপনি সমাজে সম্মানিত হবেন। তবে মনে রাখবেন—সম্পদ এলে অহংকার করবেন না, দান করুন, দুস্থদের সাহায্য করুন এবং আপনার বাক্য যেন কখনো কাউকে আঘাত না করে। বৃহস্পতি ধন ও জ্ঞান দুই-ই দেবেন, কিন্তু তার অপব্যবহার করলে কেড়েও নিতে পারেন। মধ্যকালে ফল বিশেষভাবে অনুভূত হবে।`},
            3:{type:"অশুভ",summary:"শারীরিক ক্লেশ ও ভ্রমণ কষ্ট",time:"এক বৎসর",full:`বৃহস্পতি এখন আপনার তৃতীয় ভাবে অবস্থান করছে, সাহস ও ভ্রমণের এই ভাবে গুরু গ্রহের গোচর আপনার শারীরিক ক্লেশ ও ভ্রমণজনিত কষ্টের কারণ হতে পারে। এই এক বৎসর আপনি অকারণ ভ্রমণে গিয়ে কষ্ট পেতে পারেন, ভাইবোনদের সাথে সম্পর্কে টানাপোড়েন দেখা দিতে পারে এবং আপনার লেখা বা কথার মাধ্যমে কেউ আপনার সমালোচনা করতে পারে। শরীরে অলসতা ও ক্লান্তি ভর করবে, উদ্যম কমে যাবে এবং মনে হবে আপনি যেন এগোতে পারছেন না। কিন্তু মনে রাখবেন—বৃহস্পতি তৃতীয় ভাবে তেমন শক্তিশালী নয়, তাই এই সময়ে বড় পরিকল্পনা না করাই ভালো। ছোটখাটো কাজে গিয়ে বিপদ ডেকে আনবেন না, ভাইবোনদের সাথে ধৈর্য ধরে সম্পর্ক বজায় রাখুন এবং শরীরচর্চা করে নিজেকে সক্রিয় রাখুন। এই এক বৎসর ধৈর্যের পরীক্ষা, কিন্তু এর শেষে আপনি নিজেকে আরও শক্তিশালী পাবেন। মধ্যকালে ফল বিশেষভাবে অনুভূত হবে।`},
            4:{type:"অশুভ",summary:"অর্থনাশ ও গৃহকষ্ট",time:"এক বৎসর",full:`বৃহস্পতি এখন আপনার চতুর্থ ভাবে অবস্থান করছে, সুখ, শান্তি ও মায়ের এই ভাবে গুরু গ্রহের গোচর আপনার গৃহস্থ জীবনে চ্যালেঞ্জ নিয়ে আসবে। এই এক বৎসর আপনি অর্থনাশের সম্মুখীন হতে পারেন, বাসস্থান বা যানবাহন নিয়ে অপ্রত্যাশিত ব্যয় হবে এবং মায়ের সাথে দূরত্ব বা মতবিরোধ দেখা দিতে পারে। আপনার মানসিক শান্তি নষ্ট হবে, আপনি অস্থির বোধ করবেন এবং মনে হবে আপনার সুখের নীড়ে যেন অশান্তির ঝড় বয়ে যাচ্ছে। তবে মনে রাখবেন—বৃহস্পতি চতুর্থ ভাবে নিজের শক্তি হারিয়ে ফেলে, কিন্তু তিনি আপনাকে শিক্ষা দিতে চান যে সুখ শুধু বাইরের জিনিসে নয়। ঘর ও পরিবারের প্রতি বেশি যত্নশীল হোন, অপ্রয়োজনীয় সংস্কার বা পরিবর্তন থেকে বিরত থাকুন, মায়ের সেবা করুন ও তাঁর আশীর্বাদ নিন। ধ্যান ও প্রার্থনার মাধ্যমে মানসিক শান্তি ফিরিয়ে আনুন। মধ্যকালে ফল বিশেষভাবে অনুভূত হবে।`},
            5:{type:"শুভ",summary:"শুভফল ও সন্তানসুখ",time:"এক বৎসর",full:`বৃহস্পতি এখন আপনার পঞ্চম ভাবে অবস্থান করছে, বুদ্ধি, সন্তান ও সৃজনশীলতার এই ভাবে গুরু গ্রহের গোচর আপনার রাশিচক্রের অন্যতম শ্রেষ্ঠ অবস্থান। এই এক বৎসর অত্যন্ত শুভ ফল আসবে, আপনার বুদ্ধি, জ্ঞান ও সৃজনশীলতা পূর্ণ প্রস্ফুটিত হবে এবং সন্তানের সুখ ও সাফল্য দেখে আপনি গর্বিত হবেন। নিঃসন্তানদের জন্য সন্তান লাভের যোগ তৈরি হতে পারে, প্রেমজীবনে আনন্দ ও পরিপূর্ণতা আসবে এবং আপনার সৃজনশীল কাজ চারদিকে প্রশংসিত হবে। পুণ্যকর্মে মন স্বাভাবিকভাবেই ধাবিত হবে, আপনি ধর্ম ও ন্যায়ের পথে চলতে আগ্রহী হবেন। তবে মনে রাখবেন—সুখের সময়েও সংযম হারাবেন না, সন্তানকে অতিরিক্ত প্রশ্রয় দেবেন না, তাদের সঠিক শিক্ষা দিন। প্রেম ও সৃজনশীলতাকে ইতিবাচক পথে চালনা করুন, এই এক বৎসর আপনার জীবনের স্মরণীয় সময় হয়ে থাকবে। মধ্যকালে ফল বিশেষভাবে অনুভূত হবে।`},
            6:{type:"অশুভ",summary:"অশুভ ও শত্রুভয়",time:"এক বৎসর",full:`বৃহস্পতি এখন আপনার ষষ্ঠ ভাবে অবস্থান করছে, শত্রু, রোগ ও ঋণের এই ভাবে গুরু গ্রহের গোচর তার শুভত্ব হারিয়ে ফেলে। এই এক বৎসর আপনার জীবনে অশুভ ঘটনার সূচনা হতে পারে, শত্রুভয় বৃদ্ধি পাবে এবং আপনার শত্রুরা সক্রিয় হয়ে আপনার ক্ষতি করার চেষ্টা করবে। ঋণের বোঝা বাড়তে পারে, স্বাস্থ্যের অবনতি হতে পারে—বিশেষ করে যকৃত বা পেটের সমস্যা দেখা দিতে পারে এবং মামা বা মামার পক্ষের আত্মীয়দের সাথে বিরোধ হতে পারে। তবে মনে রাখবেন—বৃহস্পতি ষষ্ঠ ভাবে দুর্বল হলেও একেবারে নিষ্ফল নয়, শত্রুর মোকাবেলা করতে গিয়ে আপনি নিজেও শক্তিশালী হয়ে উঠবেন। কৌশলী হোন, প্রকাশ্য বিবাদে জড়াবেন না, ঋণ পরিশোধের জন্য পরিকল্পনা করুন এবং স্বাস্থ্যের প্রতি যত্ন নিন। নিয়মিত ব্যায়াম ও সঠিক খাদ্যাভ্যাস আপনাকে সুস্থ রাখবে। মধ্যকালে ফল বিশেষভাবে অনুভূত হবে।`},
            7:{type:"শুভ",summary:"রাজপূজা ও বিবাহসুখ",time:"এক বৎসর",full:`বৃহস্পতি এখন আপনার সপ্তম ভাবে অবস্থান করছে, জীবনসঙ্গী ও সম্পর্কের এই ভাবে গুরু গ্রহের গোচর আপনার সম্পর্কের জগৎ স্বর্গীয় মাধুর্যে ভরিয়ে তুলবে। এই এক বৎসর আপনি রাজপূজা অর্থাৎ উচ্চপদস্থ বা রাজকীয় ব্যক্তিদের কাছ থেকে সম্মান ও স্বীকৃতি পাবেন, আপনার সামাজিক অবস্থান সুদৃঢ় হবে। বিবাহিত জীবনে দাম্পত্য সুখ চরমে পৌঁছাবে, জীবনসঙ্গীর সাথে সম্পর্ক হবে অত্যন্ত মধুর ও বোঝাপড়ায় ভরা। অবিবাহিতদের জন্য বিবাহের যোগ তৈরি হবে, ব্যবসায়িক অংশীদারিত্বে সাফল্য আসবে এবং নতুন সম্পর্ক তৈরি হবে যা আপনার জীবনে ইতিবাচক প্রভাব ফেলবে। তবে মনে রাখবেন—সম্পর্কে অহংকার অর্থহীন, জীবনসঙ্গীকে সম্মান দিন, তাঁর মতামতকে গুরুত্ব দিন। এই এক বৎসর সম্পর্কের দিক থেকে আপনার জীবনের শ্রেষ্ঠ সময় হতে চলেছে। মধ্যকালে ফল বিশেষভাবে অনুভূত হবে।`},
            8:{type:"অশুভ",summary:"ধননাশ ও উত্তরাধিকার বিবাদ",time:"এক বৎসর",full:`বৃহস্পতি এখন আপনার অষ্টম ভাবে অবস্থান করছে, রহস্য ও রূপান্তরের এই ভাবে গুরু গ্রহের গোচর আপনার আর্থিক জীবনে গভীর সংকট সৃষ্টি করতে পারে। এই এক বৎসর আপনি ধননাশের সম্মুখীন হতে পারেন, উত্তরাধিকার বা পারিবারিক সম্পত্তি নিয়ে বিবাদ বাড়তে পারে এবং শ্বশুর বা শ্বশুরবাড়ির সাথে সম্পর্কের অবনতি হতে পারে। গোপন শত্রুরা সক্রিয় হয়ে উঠবে, হঠাৎ বড় কোনো ব্যয় বা ক্ষতি হতে পারে এবং মনে হবে আপনার সমস্ত সঞ্চয় যেন হাতছাড়া হয়ে যাচ্ছে। কিন্তু মনে রাখবেন—অষ্টম ভাব রূপান্তরেরও প্রতীক, এই ক্ষতি আপনাকে নতুন করে গড়ে ওঠার শিক্ষা দেবে। বড় ঝুঁকি নেবেন না, বিনিয়োগ থেকে বিরত থাকুন, উত্তরাধিকার সংক্রান্ত কাগজপত্র গুছিয়ে রাখুন। দান-ধ্যান ও ধর্মীয় কাজে মনের শান্তি পাবেন। মধ্যকালে ফল বিশেষভাবে অনুভূত হবে।`},
            9:{type:"শুভ",summary:"ধনবৃদ্ধি ও ধর্মলাভ",time:"এক বৎসর",full:`বৃহস্পতি এখন আপনার নবম ভাবে অবস্থান করছে, ভাগ্য, ধর্ম ও গুরুর এই নিজস্ব ভাবে গুরু গ্রহের গোচর আপনার রাশিচক্রের সর্বশ্রেষ্ঠ অবস্থানগুলোর একটি। এই এক বৎসর আপনি ধনবৃদ্ধি লাভ করবেন, ধর্ম ও জ্ঞানের পথে আপনার মন স্বাভাবিকভাবেই ধাবিত হবে এবং গুরুর কৃপা লাভ হবে। পিতার সাথে সম্পর্ক অত্যন্ত মধুর হবে, উচ্চশিক্ষা বা বিদেশযাত্রা সম্ভব হবে এবং আপনার ভাগ্য পুরোপুরি জাগ্রত হবে। আপনি যেখানেই হাত দেবেন, সেখানেই সাফল্য আসবে, মানুষ আপনাকে সম্মান করবে এবং আপনার কথায় গুরুত্ব দেবে। তবে মনে রাখবেন—ভাগ্য জাগ্রত হলেও পরিশ্রম করতে হবে, শুধু ভাগ্যের উপর ভরসা করে বসে থাকলে চলবে না। গুরু ও পিতার সেবা করুন, তীর্থযাত্রা করলে বিশেষ পুণ্য লাভ হবে। এই এক বৎসর আপনার জীবনের অমূল্য সময়। মধ্যকালে ফল বিশেষভাবে অনুভূত হবে।`},
            10:{type:"অশুভ",summary:"প্রণয়ভঙ্গ ও কর্মক্ষেত্রে বাধা",time:"এক বৎসর",full:`বৃহস্পতি এখন আপনার দশম ভাবে অবস্থান করছে, কর্ম ও পেশার এই ভাবে গুরু গ্রহের গোচর আপনার কর্মজীবনে অদ্ভুত সব বাধা সৃষ্টি করতে পারে। এই এক বৎসর কর্মক্ষেত্রে প্রণয়ভঙ্গ বা প্রেমঘটিত সমস্যা তৈরি হতে পারে, আপনার কাজের স্বীকৃতি পেতে বিলম্ব হবে এবং উচ্চপদস্থ কর্তৃপক্ষের সাথে মতবিরোধ দেখা দিতে পারে। অফিসের রাজনীতি আপনার ক্ষতি করতে পারে, সহকর্মীরা আপনার বিরুদ্ধে ষড়যন্ত্র করতে পারে এবং আপনি নিজেকে একা ও অসহায় মনে করতে পারেন। তবে মনে রাখবেন—বৃহস্পতি দশম ভাবে সম্পূর্ণ শুভ ফল দিতে পারে না, কিন্তু তিনি আপনাকে ধৈর্যের শিক্ষা দেন। এই এক বৎসর নিষ্ঠার সাথে কাজ করে যান, অফিসের সহকর্মীদের সাথে বন্ধুত্বপূর্ণ সম্পর্ক রাখুন কিন্তু পেশাগত ও ব্যক্তিগত জীবনের মধ্যে সীমারেখা টানুন। ফলের আশা না করে কর্তব্য পালন করুন, সময় বদলাবে। মধ্যকালে ফল বিশেষভাবে অনুভূত হবে।`},
            11:{type:"শুভ",summary:"স্থান ও ধনলাভ",time:"এক বৎসর",full:`বৃহস্পতি এখন আপনার একাদশ ভাবে অবস্থান করছে, লাভ, আয় ও বন্ধুত্বের এই ভাবে গুরু গ্রহের গোচর আপনার আর্থিক ও সামাজিক জীবনে নতুন ভোরের সূচনা করবে। এই এক বৎসর আপনি স্থান ও ধন—দুটোই লাভ করবেন, সমাজে আপনার অবস্থান সুদৃঢ় হবে এবং ধনাগমও হবে। বন্ধুদের কাছ থেকে অপ্রত্যাশিত সাহায্য পাবেন, আপনার আয়ের একাধিক নতুন উৎস তৈরি হবে এবং ব্যবসা-বাণিজ্যে সাফল্য আসবে। আপনার উচ্চাকাঙ্ক্ষা পূর্ণ হতে চলেছে, আপনি যা স্বপ্ন দেখেছেন তা বাস্তবে রূপ নিতে শুরু করবে। তবে মনে রাখবেন—লাভের সাথে সদ্ব্যবহারও জরুরি, আপনার সম্পদ যেন সমাজের কল্যাণে লাগে, বন্ধুদের সাথে বিশ্বাসঘাতকতা করবেন না। এই এক বৎসর আপনার আর্থিক জীবনের শ্রেষ্ঠ সময় হতে চলেছে। মধ্যকালে ফল বিশেষভাবে অনুভূত হবে।`},
            12:{type:"অশুভ",summary:"শারীরিক পীড়া ও অপ্রত্যাশিত ব্যয়",time:"এক বৎসর",full:`বৃহস্পতি এখন আপনার দ্বাদশ ভাবে অবস্থান করছে, ব্যয়, মোক্ষ ও গোপন শত্রুর এই ভাবে গুরু গ্রহের গোচর আপনার জীবনে কষ্ট ও চ্যালেঞ্জের আগমন ঘটাবে। এই এক বৎসর আপনি শারীরিক পীড়ায় ভুগতে পারেন, অপ্রত্যাশিত বড় ব্যয় হবে এবং অর্থ নষ্ট হবে। বিদেশ বা প্রবাসে গিয়ে কষ্ট পেতে পারেন, গোপন শত্রুরা সক্রিয় হবে এবং হাসপাতাল বা চিকিৎসা সংক্রান্ত খরচ বৃদ্ধি পাবে। মনে হতে পারে যেন আপনার সমস্ত পরিশ্রম জলে ভেসে যাচ্ছে, কেউ আপনার মূল্য বুঝছে না। তবে মনে রাখবেন—দ্বাদশ ভাব মোক্ষেরও প্রতীক, এই কষ্ট আপনাকে জাগতিক মায়া থেকে মুক্ত হতে সাহায্য করবে। এই এক বৎসর আধ্যাত্মিক চর্চায় মনোনিবেশ করুন, ধ্যান, যোগ ও মন্ত্রজপ করুন, দান-ধ্যান ও দুস্থ সেবায় মনের শান্তি পাবেন। অন্ধকারের পরেই আলো আসে। মধ্যকালে ফল বিশেষভাবে অনুভূত হবে।`}
        };

